const request = $('Capacity Request').first().json;
const capacityResult = $('Find Available Capacity').first().json;
const healthResult = $('Get Health Status').first().json;

// Parse results
const capacity = capacityResult.result || capacityResult;
const health = healthResult.result || healthResult;

// Build recommendation
const matchingCabinets = capacity.matchingCabinets || [];
const topRecommendation = matchingCabinets[0] || null;

let recommendation = '';
let status = 'success';

if (matchingCabinets.length === 0) {
  recommendation = 'No cabinets found matching the requirements. Consider:\n' +
    '1. Reducing space or power requirements\n' +
    '2. Planning capacity expansion\n' +
    '3. Consolidating existing workloads';
  status = 'no_capacity';
} else {
  recommendation = `Found ${matchingCabinets.length} suitable cabinet(s). ` +
    `Top recommendation: ${topRecommendation.cabinetName} in ${topRecommendation.location} ` +
    `with ${topRecommendation.availableU}U space and ${topRecommendation.availablePowerKw.toFixed(1)}kW power available.`;
}

// Add health context
if (health.alerts && health.alerts.critical > 0) {
  recommendation += `\n\n⚠️ Warning: ${health.alerts.critical} critical alert(s) active in the environment.`;
}

return {
  json: {
    status,
    request: {
      requiredU: request.requiredU || 4,
      requiredPowerKw: request.requiredPowerKw || 2
    },
    recommendation,
    topCabinet: topRecommendation,
    alternativeCabinets: matchingCabinets.slice(1, 5),
    totalMatches: matchingCabinets.length,
    environmentHealth: {
      score: health.healthScore,
      status: health.status,
      pue: health.pue?.current,
      activeAlerts: health.alerts
    },
    timestamp: new Date().toISOString()
  }
};
